// services/api.js

export async function login(email, password) {
  try {
    const response = await fetch('http://localhost/api/Login.php', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({ email, password }),
    });

    if (!response.ok) {
      // Si code HTTP non 200, on récupère le message d'erreur
      const errorData = await response.json();
      throw new Error(errorData.error || 'Erreur lors de la connexion');
    }

    const data = await response.json();
    // data.user contient l'utilisateur sans mot de passe
    return data.user;
  } catch (error) {
    console.error('Erreur login API:', error);
    throw error;
  }
}
export async function register(email, password) {
  try {
    const response = await fetch('http://localhost/api/Register.php', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({ email, password }),
    });

    if (!response.ok) {
      const errorData = await response.json();
      throw new Error(errorData.error || 'Erreur lors de l\'inscription');
    }

    const data = await response.json();
    return data.user; // Retourne l'utilisateur créé
  } catch (error) {
    console.error('Erreur register API:', error);
    throw error;
  }
}
